Code:
# WRONG - JavaScript-style ternary
{{ env == 'dev' ? 'localhost' : 'production-db' }}

# CORRECT - Ansible ternary filter
{{ (env == 'dev') | ternary('localhost', 'production-db') }}

# Alternative - if/else expression
{{ 'localhost' if env == 'dev' else 'production-db' }}

# WRONG
{{ my_dict.nonexistent_key }}

# CORRECT - use default filter
{{ my_dict.nonexistent_key | default('fallback') }}

# CORRECT - use bracket notation
{{ my_dict['nonexistent_key'] | default('fallback') }}

# CORRECT - check first
{% if 'nonexistent_key' in my_dict %}
  {{ my_dict.nonexistent_key }}
{% endif %}

# WRONG
{{ "Port: " + port_number }}

# CORRECT - use string filter
{{ "Port: " + port_number | string }}

# CORRECT - use format
{{ "Port: %d" | format(port_number) }}

# Common Ansible filters
{{ my_list | to_json }}
{{ my_string | regex_replace('old', 'new') }}
{{ my_dict | combine(other_dict) }}

# If using collection filters, install first
ansible-galaxy collection install community.general

# WRONG - fails if my_list is undefined
{% for item in my_list %}
  {{ item }}
{% endfor %}

# CORRECT - default to empty list
{% for item in my_list | default([]) %}
  {{ item }}
{% endfor %}

# Without whitespace control (extra blank lines)
{% for item in list %}
{{ item }}
{% endfor %}

# With whitespace control (clean output)
{%- for item in list %}
{{ item }}
{%- endfor %}

# Or set trim_blocks in ansible.cfg
# [defaults]
# jinja2_extensions = jinja2.ext.loopcontrols

# WRONG - Python syntax
{% if x == 1 %}
  one
elif x == 2:
  two
{% endif %}

# CORRECT - Jinja2 syntax
{% if x == 1 %}
  one
{% elif x == 2 %}
  two
{% else %}
  other
{% endif %}
